const body = $input.first().json.body;
const message = body.business_message;
const chatId = message.chat.id;
const businessId = message.business_connection_id;
const messageId = message.message_id;

return [{
  chat_id: chatId,
  business_connection_id: businessId,
  reply_to_message_id: messageId
}];

const forexData = $input.first().json;
const originalData = $('Parse Currency Request').item.json;

const currencyPairs = [
  { symbol: 'FX_IDC:EURUSD', name: 'EUR/USD' },
  { symbol: 'FX_IDC:GBPUSD', name: 'GBP/USD' },
  { symbol: 'FX_IDC:USDJPY', name: 'USD/JPY' },
  { symbol: 'FX_IDC:USDRUB', name: 'USD/RUB' },
  { symbol: 'FX_IDC:USDCNY', name: 'USD/CNY' },
  { symbol: 'FX_IDC:USDTHB', name: 'USD/THB' },
  { symbol: 'FX_IDC:USDAED', name: 'USD/AED' },
  { symbol: 'FX_IDC:CNYRUB', name: 'CNY/RUB' },
  { symbol: 'FX_IDC:USDCHF', name: 'USD/CHF' },
  { symbol: 'FX_IDC:AUDUSD', name: 'AUD/USD' }
];

const dataMap = {};
if (forexData.data && Array.isArray(forexData.data)) {
  for (const item of forexData.data) {
    if (item.s && item.d && item.d.length >= 2) {
      dataMap[item.s] = {
        price: item.d[0],
        change: item.d[1]
      };
    }
  }
}

const results = [];
for (const pair of currencyPairs) {
  const data = dataMap[pair.symbol];
  if (data) {
    results.push({
      name: pair.name,
      price: parseFloat(data.price).toFixed(4),
      change: parseFloat(data.change).toFixed(2)
    });
  }
}

if (results.length === 0) {
  return [{
    chat_id: originalData.chat_id,
    text: "❌ Not found.",
    business_connection_id: originalData.business_connection_id,
    reply_to_message_id: originalData.reply_to_message_id
  }];
}

let text = `💱 *Currency rates (Forex 24h)*\n\n`;
for (let i = 0; i < results.length; i++) {
  const curr = results[i];
  const trend = curr.change >= 0 ? '📈' : '📉';
  const changeSign = curr.change >= 0 ? '+' : '';
  text += `${i+1}. *${curr.name}*: ${trend} ${curr.price} (${changeSign}${curr.change}%)\n`;
}

return [{
  chat_id: originalData.chat_id,
  text: text,
  parse_mode: "Markdown",
  business_connection_id: originalData.business_connection_id,
  reply_to_message_id: originalData.reply_to_message_id
}];
